// Transform Notion page into the normalized deal payload the match engine expects
const page = $json;
const props = page.properties || {};

// Helper to safely extract values from Notion property types
const getSelect = (p) => p && p.select ? p.select.name : '';
const getMultiSelect = (p) => p && p.multi_select ? p.multi_select.map(s => s.name).join(', ') : '';
const getText = (p) => {
  if (!p) return '';
  if (p.title) return (p.title[0] && p.title[0].plain_text) || '';
  if (p.rich_text) return (p.rich_text[0] && p.rich_text[0].plain_text) || '';
  return '';
};
const getNumber = (p) => p && typeof p.number === 'number' ? p.number : 0;
const getUrl = (p) => p && p.url ? p.url : '';

const deal = {
  deal_id: page.id,
  source: 'notion',
  asset_class: getMultiSelect(props['Asset Class']) || getSelect(props['Asset Class']),
  market: getText(props['Market']),
  price: getNumber(props['Price']),
  deal_type: getSelect(props['Deal Type']) || 'Wholesale',
  summary_url: getUrl(props['Summary URL']),
  address: getText(props['Address']),
  notion_page_id: page.id
};

return [{ json: deal }];
